INSERT INTO album (facility_id, author_id, activity_date, title, description, photos, created_at, updated_at) VALUES (1, 2, '2026-05-23', '봄 나들이 산책', '따뜻한 봄날, 어르신들과 함께 시설 정원을 산책했습니다.', '[{"url":"/static/albums/2026/05/album_garden.png","uploadedAt":"2026-05-30T01:30:43.429801+00:00"}]'::jsonb, '2026-05-30T01:30:43.429801+00:00', '2026-05-30T01:30:43.429801+00:00');
INSERT INTO album (facility_id, author_id, activity_date, title, description, photos, created_at, updated_at) VALUES (1, 2, '2026-05-26', '실버 체조 교실', '전문 강사와 함께 어르신 맞춤 스트레칭 프로그램을 진행했습니다.', '[{"url":"/static/albums/2026/05/album_exercise.png","uploadedAt":"2026-05-30T01:30:43.429801+00:00"}]'::jsonb, '2026-05-30T01:30:43.429801+00:00', '2026-05-30T01:30:43.429801+00:00');
INSERT INTO album (facility_id, author_id, activity_date, title, description, photos, created_at, updated_at) VALUES (1, 2, '2026-05-28', '미술 치료 활동', '수채화 꽃 그리기로 어르신들의 감성을 자극하는 시간을 가졌습니다.', '[{"url":"/static/albums/2026/05/album_art.png","uploadedAt":"2026-05-30T01:30:43.429801+00:00"},{"url":"/static/albums/2026/05/album_craft.png","uploadedAt":"2026-05-30T01:30:43.429801+00:00"}]'::jsonb, '2026-05-30T01:30:43.429801+00:00', '2026-05-30T01:30:43.429801+00:00');
INSERT INTO album (facility_id, author_id, activity_date, title, description, photos, created_at, updated_at) VALUES (1, 2, '2026-05-30', '음악 치료 시간', '익숙한 노래를 함께 부르며 즐거운 음악 치료 시간을 보냈습니다.', '[{"url":"/static/albums/2026/05/album_music.png","uploadedAt":"2026-05-30T01:30:43.429801+00:00"}]'::jsonb, '2026-05-30T01:30:43.429801+00:00', '2026-05-30T01:30:43.429801+00:00');
INSERT INTO album (facility_id, author_id, activity_date, title, description, photos, created_at, updated_at) VALUES (1, 2, '2026-06-01', '6월 맞이 정원 산책', '6월 첫날을 맞아 어르신들과 정원에서 신선한 공기를 마셨습니다.', '[{"url":"/static/albums/2026/05/album_garden.png","uploadedAt":"2026-05-30T01:30:43.429801+00:00"},{"url":"/static/albums/2026/05/album_exercise.png","uploadedAt":"2026-05-30T01:30:43.429801+00:00"}]'::jsonb, '2026-05-30T01:30:43.429801+00:00', '2026-05-30T01:30:43.429801+00:00');

INSERT INTO album_resident (album_id, resident_id)
SELECT a.id, r.id
FROM album a
CROSS JOIN resident r
WHERE r.facility_id = 1
  AND r.deleted_at IS NULL
  AND a.facility_id = 1
  AND a.deleted_at IS NULL
  AND NOT EXISTS (SELECT 1 FROM album_resident ar WHERE ar.album_id = a.id AND ar.resident_id = r.id)
ON CONFLICT DO NOTHING;

